91	/////////////////////////////////////////////////////////////////////////////////////////////////
92	/// GEMM kernel configurations
93	/////////////////////////////////////////////////////////////////////////////////////////////////
94	
95	// A matrix configuration
96	using         ElementA    = cutlass::nv_float4_t<cutlass::float_e2m1_t>;    // Element type for A matrix operand
97	using         LayoutATag  = cutlass::layout::RowMajor;                      // Layout type for A matrix operand
98	constexpr int AlignmentA  = 32;                                             // Memory access granularity/alignment of A matrix in units of elements (up to 16 bytes)
99	
100	// B matrix configuration
101	using         ElementB    = cutlass::nv_float4_t<cutlass::float_e2m1_t>;    // Element type for A matrix operand
102	using         LayoutBTag  = cutlass::layout::ColumnMajor;                   // Layout type for B matrix operand
103	constexpr int AlignmentB  = 32;                                             // Memory access granularity/alignment of B matrix in units of elements (up to 16 bytes)
104	
105	// C/D matrix configuration
106	using         ElementD    = cutlass::bfloat16_t;                            // Element type for D matrix operand
107	using         ElementC    = cutlass::bfloat16_t;                            // Element type for C matrix operand
108	using         LayoutCTag  = cutlass::layout::RowMajor;                      // Layout type for C matrix operand
109	using         LayoutDTag  = cutlass::layout::RowMajor;                      // Layout type for D matrix operand
110	constexpr int AlignmentD  = 128 / cutlass::sizeof_bits<ElementD>::value;    // Memory access granularity/alignment of C matrix in units of elements (up to 16 bytes)
111	constexpr int AlignmentC  = 128 / cutlass::sizeof_bits<ElementC>::value;    // Memory access granularity/alignment of C matrix in units of elements (up to 16 bytes)
112	// Kernel functional config
113	using ElementAccumulator  = float;                                          // Element type for internal accumulation
114	using ArchTag             = cutlass::arch::Sm100;                           // Tag indicating the minimum SM that supports the intended feature
115	using OperatorClass       = cutlass::arch::OpClassBlockScaledTensorOp;      // Operator class tag
116	
117	// Kernel Perf config
118	using MmaTileShape        = Shape<_256,_256,_256>;                          // MMA's tile size
119	using ClusterShape        = Shape<_2,_4,_1>;                                // Shape of the threadblocks in a cluster
120	
121	using CollectiveEpilogue = typename cutlass::epilogue::collective::CollectiveBuilder<
122	    ArchTag, OperatorClass,
123	    MmaTileShape, ClusterShape,
124	    cutlass::epilogue::collective::EpilogueTileAuto,
125	    ElementAccumulator, ElementAccumulator,
126	    ElementC, LayoutCTag, AlignmentC,
127	    ElementD, LayoutDTag, AlignmentD,
128	    cutlass::epilogue::collective::EpilogueScheduleAuto                      // Epilogue schedule policy
129	  >::CollectiveOp;
130	
131	using CollectiveMainloop = typename cutlass::gemm::collective::CollectiveBuilder<
132	    ArchTag, OperatorClass,
133	    ElementA, LayoutATag, AlignmentA,
134	    ElementB, LayoutBTag, AlignmentB,
135	    ElementAccumulator,
136	    MmaTileShape, ClusterShape,
137	    cutlass::gemm::collective::StageCountAutoCarveout<static_cast<int>(sizeof(typename CollectiveEpilogue::SharedStorage))>,
138	    cutlass::gemm::collective::KernelScheduleAuto                             // Kernel schedule policy. Auto or using targeted scheduling policy
139	  >::CollectiveOp;
140	
141	using GemmKernel = cutlass::gemm::kernel::GemmUniversal<
142	    Shape<int,int,int,int>,                                                   // Indicates ProblemShape
143	    CollectiveMainloop,
144	    CollectiveEpilogue,
145	    void>;
146	
147	using Gemm = cutlass::gemm::device::GemmUniversalAdapter<GemmKernel>;
148	
149	// Reference device GEMM implementation type
150	using StrideA   = typename Gemm::GemmKernel::StrideA;
151	using LayoutA   = decltype(cute::make_layout(make_shape(0,0,0), StrideA{}));
152	using LayoutSFA = typename Gemm::GemmKernel::CollectiveMainloop::LayoutSFA;      // Scale Factor tensors have an interleaved layout. Bring Layout instead of stride.
153	using StrideB   = typename Gemm::GemmKernel::StrideB;
154	using LayoutB   = decltype(cute::make_layout(make_shape(0,0,0), StrideB{}));
155	using LayoutSFB = typename Gemm::GemmKernel::CollectiveMainloop::LayoutSFB;      // Scale Factor tensors have an interleaved layout. Bring Layout instead of stride.
156	using StrideC   = typename Gemm::GemmKernel::StrideC;
157	using LayoutC   = decltype(cute::make_layout(make_shape(0,0,0), StrideC{}));
158	using StrideD   = typename Gemm::GemmKernel::StrideD;
159	using LayoutD   = decltype(cute::make_layout(make_shape(0,0,0), StrideD{}));
160	
161	//
162	// Data members
163	//
164	
165	/// Initialization
166	StrideA stride_A;
167	LayoutA layout_A;
168	LayoutSFA layout_SFA;
169	StrideB stride_B;
170	LayoutB layout_B;
171	LayoutSFB layout_SFB;
172	StrideC stride_C;
173	LayoutC layout_C;
174	StrideD stride_D;
175	LayoutD layout_D;
176	uint64_t seed;
177	
178	// The HostTensors are only used for allocating memory on host and device, and transferring data between host and device
179	// Use cute::Tensor and cute::Layout for iterating thru the matrix elements
180	cutlass::HostTensor<ElementA::DataType, cutlass::layout::PackedVectorLayout> block_A;
181	cutlass::HostTensor<ElementA::ScaleFactorType, cutlass::layout::PackedVectorLayout> block_SFA;
182	cutlass::HostTensor<ElementB::DataType, cutlass::layout::PackedVectorLayout> block_B;
183	cutlass::HostTensor<ElementB::ScaleFactorType, cutlass::layout::PackedVectorLayout> block_SFB;
184	cutlass::HostTensor<ElementC, cutlass::layout::PackedVectorLayout> block_C;
185	// Output Tensor
186	cutlass::HostTensor<ElementD, cutlass::layout::PackedVectorLayout> block_D;
187	// Reference Output Tensor
188	cutlass::HostTensor<ElementD, cutlass::layout::PackedVectorLayout> block_reference_D;
189	#endif // defined(CUTLASS_ARCH_MMA_SM100_SUPPORTED)
