200	// Command line options parsing
201	struct Options {
202	
203	  bool help;
204	
205	  float alpha, beta;
206	  int iterations;
207	  int m, n, k;
208	  int swizzle = 0;
209	
210	  Options():
211	    help(false),
212	    m(1024), n(1024), k(1024),
213	    alpha(1.f), beta(0.f),
214	    iterations(10),
215	    swizzle(0)
216	  { }
217	
218	  // Parses the command line
219	  void parse(int argc, char const **args) {
220	    cutlass::CommandLine cmd(argc, args);
221	
222	    if (cmd.check_cmd_line_flag("help")) {
223	      help = true;
224	      return;
225	    }
226	
227	    cmd.get_cmd_line_argument("m", m);
228	    cmd.get_cmd_line_argument("n", n);
229	    cmd.get_cmd_line_argument("k", k);
230	    cmd.get_cmd_line_argument("alpha", alpha, 1.f);
231	    cmd.get_cmd_line_argument("beta", beta, 0.f);
232	    cmd.get_cmd_line_argument("iterations", iterations);
233	    cmd.get_cmd_line_argument("swizzle", swizzle);
234	  }
235	
236	  /// Prints the usage statement.
237	  std::ostream & print_usage(std::ostream &out) const {
238	
239	    out << "72a_blackwell_nvfp4_bf16_gemm\n\n"
240	      << "  Blackwell NVFP4 GEMM using a Warp Specialized kernel.\n\n"
241	      << "Options:\n\n"
242	      << "  --help                      If specified, displays this usage statement\n\n"
243	      << "  --m=<int>                   Sets the M extent of the GEMM\n"
244	      << "  --n=<int>                   Sets the N extent of the GEMM\n"
245	      << "  --k=<int>                   Sets the K extent of the GEMM\n"
246	      << "  --alpha=<f32>               Epilogue scalar alpha\n"
247	      << "  --beta=<f32>                Epilogue scalar beta\n"
248	      << "  --swizzle=<int>             Cluster rasterization swizzle\n"
249	      << "  --iterations=<int>          Number of profiling iterations to perform.\n\n";
250	
251	    out << "\n\nExamples:\n\n"
252	      << "$ " << "./examples/72_blackwell_narrow_precision_gemm/72a_blackwell_nvfp4_bf16_gemm" << " --m=1024 --n=512 --k=1024 --alpha=2 --beta=0.707 \n\n";
253	
254	    return out;
255	  }
256	
257	  /// Compute performance in GFLOP/s
258	  double gflops(double runtime_s) const
259	  {
260	    // Two flops per multiply-add
261	    uint64_t flop = uint64_t(2) * m * n * k;
262	    double gflop = double(flop) / double(1.0e9);
263	    return gflop / runtime_s;
264	  }
265	};
