275	
276	  Result(
277	    double avg_runtime_ms = 0,
278	    double gflops = 0,
279	    cutlass::Status status = cutlass::Status::kSuccess,
280	    cudaError_t error = cudaSuccess)
281	  :
282	    avg_runtime_ms(avg_runtime_ms), gflops(gflops), status(status), error(error), passed(false)
283	  {}
