289	/////////////////////////////////////////////////////////////////////////////////////////////////
290	/// GEMM setup and evaluation
291	/////////////////////////////////////////////////////////////////////////////////////////////////
292	
293	/// Helper to initialize a block of device data
294	template <typename Element, typename Layout>
295	bool initialize_block(
296	  cutlass::TensorView<Element, Layout> view,
297	  uint64_t seed) {
298	
299	  double scope_max, scope_min;
300	  constexpr int bits_input = cutlass::sizeof_bits<Element>::value;
301	
302	  if constexpr (bits_input == 1) {
303	    scope_max = 2;
304	    scope_min = 0;
305	  }
306	  else if constexpr (bits_input <= 6) {
307	    scope_max = 2;
308	    scope_min = -2;
309	  }
310	  else if constexpr (bits_input <= 8) {
311	    if constexpr (cute::is_same_v<Element, cutlass::float_ue8m0_t>) {
312	      scope_max = 4;
313	      scope_min = 1;
314	    }
315	    else {
316	      scope_max = 1;
317	      scope_min = -1;
318	    }
319	  }
320	  else{
321	    scope_max = 4;
322	    scope_min = -4;
323	  }
324	  cutlass::reference::host::TensorFillRandomUniform(
325	    view, seed, scope_max, scope_min, 0);
326	
327	  return true;
328	}
329	
330	/// Initialize operands to be used in the GEMM and reference GEMM
331	void initialize(const Options &options) {
332	  using namespace cute;
333	  // For SFA and SFB tensors layouts
334	  using Sm1xxBlkScaledConfig =  typename Gemm::GemmKernel::CollectiveMainloop::Sm1xxBlkScaledConfig;
335	
336	  stride_A = cutlass::make_cute_packed_stride(StrideA{}, {options.m, options.k, 1});
337	  stride_B = cutlass::make_cute_packed_stride(StrideB{}, {options.n, options.k, 1});
338	  stride_C = cutlass::make_cute_packed_stride(StrideC{}, {options.m, options.n, 1});
339	  stride_D = cutlass::make_cute_packed_stride(StrideD{}, {options.m, options.n, 1});
340	
341	  layout_A = make_layout(make_shape(options.m, options.k, 1), stride_A);
342	  layout_B = make_layout(make_shape(options.n, options.k, 1), stride_B);
343	  layout_C = make_layout(make_shape(options.m, options.n, 1), stride_C);
344	  layout_D = make_layout(make_shape(options.m, options.n, 1), stride_D);
345	  layout_SFA = Sm1xxBlkScaledConfig::tile_atom_to_shape_SFA(cute::make_shape(options.m, options.n, options.k, 1));
346	  layout_SFB = Sm1xxBlkScaledConfig::tile_atom_to_shape_SFB(cute::make_shape(options.m, options.n, options.k, 1));
347	
348	  block_A.reset(cutlass::make_Coord(size(layout_A)));
349	  block_B.reset(cutlass::make_Coord(size(layout_B)));
350	  block_C.reset(cutlass::make_Coord(size(layout_C)));
351	  block_D.reset(cutlass::make_Coord(size(layout_D)));
352	  block_reference_D.reset(cutlass::make_Coord(size(layout_D)));
353	  block_SFA.reset(cutlass::make_Coord(size(filter_zeros(layout_SFA))));
354	  block_SFB.reset(cutlass::make_Coord(size(filter_zeros(layout_SFB))));
355	
356	  initialize_block(block_A.host_view(), seed + 2021);
357	  initialize_block(block_B.host_view(), seed + 2022);
358	  initialize_block(block_C.host_view(), seed + 2023);
359	  initialize_block(block_SFA.host_view(), seed + 2024);
360	  initialize_block(block_SFB.host_view(), seed + 2025);
361	
362	  block_A.sync_device();
363	  block_B.sync_device();
364	  block_C.sync_device();
365	  block_SFA.sync_device();
366	  block_SFB.sync_device();
367	}
