369	// Populates a Gemm::Arguments structure from the given commandline options
370	typename Gemm::Arguments args_from_options(const Options &options)
371	{
372	  typename Gemm::Arguments arguments {
373	    cutlass::gemm::GemmUniversalMode::kGemm,
374	    {options.m, options.n, options.k, 1},
375	    { // Mainloop arguments
376	      block_A.device_data(), stride_A,
377	      block_B.device_data(), stride_B,
378	      block_SFA.device_data(), layout_SFA,
379	      block_SFB.device_data(), layout_SFB
380	    },
381	    { // Epilogue arguments
382	      {options.alpha, options.beta},
383	      block_C.device_data(), stride_C,
384	      block_D.device_data(), stride_D
385	    }
386	  };
387	
388	  arguments.scheduler.max_swizzle_size = options.swizzle;
389	  return arguments;
390	}
391	
392	bool verify(const Options &options) {
393	  using namespace cute;
394	  // Create the arguments for host reference implementation
395	  Tensor tensor_A = make_tensor(make_iterator(block_A.host_data()), layout_A);
396	  Tensor tensor_SFA = make_tensor(block_SFA.host_data(), layout_SFA);
397	  Tensor tensor_B = make_tensor(make_iterator(block_B.host_data()), layout_B);
398	  Tensor tensor_SFB = make_tensor(block_SFB.host_data(), layout_SFB);
399	
400	  cutlass::reference::host::GettBlockScalingMainloopParams<
401	      ElementAccumulator,                 // ElementAccumulator
402	      decltype(tensor_A),                 // TensorA
403	      decltype(tensor_SFA),               // TensorSfA
404	      decltype(tensor_B),                 // TensorB
405	      decltype(tensor_SFB)                // TensorSfB
406	    > mainloop_params{tensor_A, tensor_SFA, tensor_B, tensor_SFB};
407	
408	  auto tensor_C = cute::make_tensor(make_iterator(block_C.host_data()), layout_C);
409	  auto tensor_D = cute::make_tensor(make_iterator(block_reference_D.host_data()), layout_D);
410	
411	  cutlass::reference::host::GettBlockScalingEpilogueParams<
412	      ElementAccumulator,                   // ElementScalar
413	      ElementAccumulator,                   // ElementAccumulator
414	      ElementAccumulator,                   // ElementCompute
415	      decltype(tensor_C),                   // TensorC
416	      decltype(tensor_D)                    // TensorD
417	    > epilogue_params{options.alpha, options.beta, tensor_C, tensor_D};
418	
419	  cutlass::reference::host::Gemm3x(mainloop_params, epilogue_params);
420	
421	  // Comparison
422	  block_D.sync_host();
423	  bool passed = cutlass::reference::host::TensorEquals(block_reference_D.host_view(), block_D.host_view());
424	  passed &= (cutlass::reference::host::TensorNorm(block_reference_D.host_view()) > 0);
425	  passed &= (cutlass::reference::host::TensorNorm(block_D.host_view()) > 0);
426	
427	  return passed;
428	}
