430	/// Execute a given example GEMM computation
431	template <typename Gemm>
432	int run(Options &options)
433	{
434	  initialize(options);
435	
436	  // Instantiate CUTLASS kernel depending on templates
437	  Gemm gemm;
438	
439	  // Create a structure of gemm kernel arguments suitable for invoking an instance of Gemm
440	  auto arguments = args_from_options(options);
441	
442	  // Using the arguments, query for extra workspace required for matrix multiplication computation
443	  size_t workspace_size = Gemm::get_workspace_size(arguments);
444	
445	  // Allocate workspace memory
446	  cutlass::device_memory::allocation<uint8_t> workspace(workspace_size);
447	
448	  // Check if the problem size is supported or not
449	  CUTLASS_CHECK(gemm.can_implement(arguments));
450	
451	  // Initialize CUTLASS kernel with arguments and workspace pointer
452	  CUTLASS_CHECK(gemm.initialize(arguments, workspace.get()));
453	
454	  // Correctness / Warmup iteration
455	  CUTLASS_CHECK(gemm.run());
456	
457	  cudaDeviceSynchronize();
458	
459	  // Check if output from CUTLASS kernel and reference kernel are equal or not
460	  Result result;
461	  result.passed = verify(options);
462	
463	  std::cout << "  Disposition: " << (result.passed ? "Passed" : "Failed") << std::endl;
464	
465	  if (!result.passed) {
466	    exit(-1);
467	  }
468	
469	  // Run profiling loop
470	  if (options.iterations > 0)
471	  {
472	    GpuTimer timer;
473	    timer.start();
474	    for (int iter = 0; iter < options.iterations; ++iter) {
475	      CUTLASS_CHECK(gemm.initialize(arguments, workspace.get()));
476	      CUTLASS_CHECK(gemm.run());
477	    }
478	    timer.stop();
479	
480	    // Compute average runtime and GFLOPs.
481	    float elapsed_ms = timer.elapsed_millis();
482	    result.avg_runtime_ms = double(elapsed_ms) / double(options.iterations);
483	    result.gflops = options.gflops(result.avg_runtime_ms / 1000.0);
484	
485	
486	    std::cout << "  Problem Size: " << options.m << 'x' << options.n << 'x' << options.k << std::endl;
487	    std::cout << "  Avg runtime: " << result.avg_runtime_ms << " ms" << std::endl;
488	    std::cout << "  GFLOPS: " << result.gflops << std::endl;
489	  }
490	
491	  return 0;
492	}
