498	int main(int argc, char const **args) {
499	
500	  // CUTLASS must be compiled with CUDA 12.8 or higher Toolkit to run this example
501	  // and must have compute capability at least 100.
502	  if (__CUDACC_VER_MAJOR__ < 12 || (__CUDACC_VER_MAJOR__ == 12 && __CUDACC_VER_MINOR__ < 8)) {
503	    std::cerr << "This example requires CUDA 12.8 or newer." << std::endl;
504	    // Returning zero so this test passes on older Toolkits. Its actions are no-op.
505	    return 0;
506	  }
507	
508	  cudaDeviceProp props;
509	  int current_device_id;
510	  CUDA_CHECK(cudaGetDevice(&current_device_id));
511	
512	  CUDA_CHECK(cudaGetDeviceProperties(&props, current_device_id));
513	
514	  if (props.major != 10 || (props.minor != 0 && props.minor != 1 && props.minor != 3)) {
515	    std::cerr << "This example requires a GPU with compute capability 100a|f, 101a|f, or 103a|f)." << std::endl;
516	    return 0;
517	  } 
518	
519	  //
520	  // Parse options
521	  //
522	
523	  Options options;
524	
525	  options.parse(argc, args);
526	
527	  if (options.help) {
528	    options.print_usage(std::cout) << std::endl;
529	    return 0;
530	  }
531	
532	  //
533	  // Evaluate CUTLASS kernels
534	  //
535	#if defined(CUTLASS_ARCH_MMA_SM100_SUPPORTED)
536	  run<Gemm>(options);
537	#endif // defined(CUTLASS_ARCH_MMA_SM100_SUPPORTED)
538	
539	  return 0;
540	}
